import { useState, useEffect, useCallback } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useMutation, useQuery } from '@tanstack/react-query';
import { ArrowLeft, Building2, Star, Globe, MapPin, CheckCircle, ChevronRight, User, ExternalLink, AlertCircle } from 'lucide-react';
import { useLocation } from 'wouter';
import { SEOHead, createBreadcrumbStructuredData } from "@/components/SEOHead";

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { Breadcrumbs } from '@/components/Breadcrumbs';
import { apiRequest } from '@/lib/queryClient';
import comcubesIcon from "@assets/Artboard 17 copy 3_1758850589536.png";
import paystackLogo from "@assets/Paystack Icon_1762301215124.jpg";
import paypalLogo from "@assets/Paypal Icon_1762300482205.jpg";
import { normalizeUrl } from '@/lib/urlUtils';

const companyListingSchema = z.object({
  companyName: z.string().min(2, 'Company name must be at least 2 characters'),
  email: z.string().email('Please enter a valid email address'),
  phone: z.string().min(10, 'Phone number must be at least 10 digits'),
  website: z.string()
    .min(1, 'Website is required')
    .transform((value) => {
      const result = normalizeUrl(value);
      return result.normalizedUrl;
    })
    .refine((value) => {
      const result = normalizeUrl(value);
      return result.isValid;
    }, 'Please enter a valid website URL'),
  contactPerson: z.string().min(2, 'Contact person name must be at least 2 characters'),
  businessSector: z.string().min(1, 'Please select a business sector'),
  industry: z.string().min(1, 'Please select an industry'),
  companyDescription: z.string().min(50, 'Company description must be at least 50 characters'),
  companyLogo: z.string().optional(),
  listingPlan: z.enum(['basic', 'premium'], {
    required_error: 'Please select a listing plan',
  }),
  paymentAmount: z.string().optional(),
});

type CompanyListingData = z.infer<typeof companyListingSchema>;

// Fetch sectors from API instead of hardcoded list

// Remove hardcoded industries object - we'll fetch from API

export default function ListCompanyPage() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [step, setStep] = useState<'form' | 'payment' | 'success'>('form');
  const [listingId, setListingId] = useState<number | null>(null);
  const [selectedPlan, setSelectedPlan] = useState<'basic' | 'premium' | null>(null);
  const [selectedSector, setSelectedSector] = useState<string>('');
  const [isWaitlisted, setIsWaitlisted] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<'paypal' | 'paystack'>('paystack');
  const [exchangeRate, setExchangeRate] = useState<number | null>(null);
  const [isLoadingRate, setIsLoadingRate] = useState(false);

  // Feature flag: PayPal visibility (enabled in development, disabled in production by default)
  const isPayPalEnabled = import.meta.env.VITE_PAYPAL_ENABLED === 'true';

  // URL validation state
  const [urlToCheck, setUrlToCheck] = useState<string>('');
  const [urlCheckDebounceTimer, setUrlCheckDebounceTimer] = useState<NodeJS.Timeout | null>(null);

  // Get URL parameters for smart form population
  const urlParams = new URLSearchParams(window.location.search);
  const preSelectedSector = urlParams.get('sector') || '';
  const preSelectedIndustry = urlParams.get('industry') || '';

  // Fetch sectors from API
  const { data: sectors } = useQuery({
    queryKey: ['/api/sectors'],
    staleTime: 300000, // 5 minutes
  });

  const form = useForm<CompanyListingData>({
    resolver: zodResolver(companyListingSchema),
    defaultValues: {
      companyName: '',
      email: '',
      phone: '',
      website: '',
      contactPerson: '',
      businessSector: preSelectedSector,
      industry: preSelectedIndustry,
      companyDescription: '',
    },
  });

  // URL checking functionality
  const { data: urlCheckResult, isLoading: isCheckingUrl } = useQuery({
    queryKey: ['/api/url-check', urlToCheck],
    queryFn: async ({ queryKey }) => {
      const [, url] = queryKey;
      if (!url) return null;
      const response = await fetch(`/api/url-check?u=${encodeURIComponent(url as string)}`);
      return response.json();
    },
    enabled: !!urlToCheck,
    staleTime: 300000, // 5 minutes
    retry: false
  });

  // Debounced URL handler
  const handleUrlChange = useCallback((value: string) => {
    // Clear existing timer
    if (urlCheckDebounceTimer) {
      clearTimeout(urlCheckDebounceTimer);
    }

    // Don't check empty values
    if (!value.trim()) {
      setUrlToCheck('');
      return;
    }

    // Normalize the URL first to check what we'll actually be validating
    const normalizedResult = normalizeUrl(value);
    if (!normalizedResult.isValid) {
      setUrlToCheck('');
      return;
    }

    // Set up new debounced check
    const timer = setTimeout(() => {
      setUrlToCheck(normalizedResult.normalizedUrl);
    }, 600); // 600ms debounce

    setUrlCheckDebounceTimer(timer);
  }, [urlCheckDebounceTimer]);

  // Fetch exchange rate when payment method changes to Paystack (USD-only mode: disabled by default)
  useEffect(() => {
    const fetchExchangeRate = async () => {
      if (paymentMethod === 'paystack' && listingId) {
        setIsLoadingRate(true);
        try {
          const response = await fetch('/api/currency/usd-to-ngn');
          const data = await response.json();

          // Check if currency conversion is disabled (USD-only mode)
          if (data.disabled) {
            console.log('Currency conversion disabled - USD-only mode active');
            setExchangeRate(null);
          } else if (data.rate) {
            setExchangeRate(data.rate);
          }
        } catch (error) {
          console.log('Exchange rate fetch failed (USD-only mode):', error);
          setExchangeRate(null);
        } finally {
          setIsLoadingRate(false);
        }
      }
    };

    fetchExchangeRate();
  }, [paymentMethod, listingId]);

  // Scroll to top when component mounts
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  // Auto-populate fields from URL parameters
  useEffect(() => {
    if (preSelectedSector) {
      form.setValue('businessSector', preSelectedSector);
      setSelectedSector(preSelectedSector);
    }
    if (preSelectedIndustry) {
      form.setValue('industry', preSelectedIndustry);
    }
    console.log('Smart autofill applied:', { preSelectedSector, preSelectedIndustry });
  }, [preSelectedSector, preSelectedIndustry, form]);

  const listingMutation = useMutation({
    mutationFn: async (data: CompanyListingData) => {
      // Map form data to backend schema
      const mappedData = {
        companyName: data.companyName,
        websiteUrl: data.website,
        contactEmail: data.email,
        sectorName: data.businessSector,
        industryName: data.industry,
        description: data.companyDescription,
        logoUrl: data.companyLogo || '',
        listingPlan: data.listingPlan,
        paymentAmount: data.paymentAmount || '',
      };
      const response = await apiRequest('POST', '/api/company-listing', mappedData);
      return response.json();
    },
    onSuccess: (result) => {
      if (result.isWaitlisted) {
        setIsWaitlisted(true);
        toast({
          title: "Added to Waitlist",
          description: result.message,
          variant: "default",
        });
        setStep('success');
      } else {
        setIsWaitlisted(false);
        setListingId(result.listingId);
        setStep('payment');
        toast({
          title: "Listing Submitted Successfully",
          description: "Now proceed with payment to activate your listing.",
        });
      }
    },
    onError: (error) => {
      toast({
        title: "Failed to Submit Application",
        description: error.message || "Please try again later.",
        variant: "destructive",
      });
    },
  });

  const paymentMutation = useMutation({
    mutationFn: async (data: { listingId: number; amount: number; paymentMethod: string }) => {
      const response = await apiRequest('POST', '/api/payment/initialize', data);
      return response.json();
    },
    onSuccess: (result) => {
      if (result.paymentMethod === 'paypal' && result.approval_url) {
        // Redirect to PayPal payment page
        window.location.href = result.approval_url;
      } else if (result.paymentMethod === 'paystack' && result.authorization_url) {
        // Redirect to Paystack payment page
        window.location.href = result.authorization_url;
      } else {
        toast({
          title: "Payment Setup Failed",
          description: "Could not initialize payment. Please try again.",
          variant: "destructive",
        });
      }
    },
    onError: (error) => {
      toast({
        title: "Payment Failed",
        description: error.message || "Please try again later.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: CompanyListingData) => {
    // Set the payment amount and plan in the data
    const formDataWithPayment = {
      ...data,
      listingPlan: selectedPlan!,
      paymentAmount: selectedPlan === 'basic' ? '6000' : '9000', // Quarterly billing: Basic $60, Premium $90
    };
    listingMutation.mutate(formDataWithPayment);
  };

  const handlePayment = () => {
    if (listingId && selectedPlan) {
      const amount = selectedPlan === 'basic' ? 6000 : 9000; // Quarterly billing: Basic $60, Premium $90
      paymentMutation.mutate({
        listingId,
        amount,
        paymentMethod,
      });
    }
  };

  const watchedSector = form.watch('businessSector');

  // Fetch industries when sector is selected
  const { data: industriesData } = useQuery({
    queryKey: [`/api/sectors/${watchedSector}/industries`],
    enabled: !!watchedSector,
    staleTime: 300000, // 5 minutes
  });

  const availableIndustries = industriesData || [];

  // Reset industry when sector changes (but not during initial URL parameter population)
  useEffect(() => {
    if (watchedSector && !preSelectedSector && !preSelectedIndustry) {
      form.setValue('industry', ''); // Reset industry selection only if not from URL params
    }
  }, [watchedSector, form, preSelectedSector, preSelectedIndustry]);

  // Payment step component
  const renderPayment = () => (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center py-4">
            <div className="flex items-center cursor-pointer hover:opacity-80 transition-opacity" onClick={() => setLocation('/')}>
              <div className="w-16 h-16 mr-3 flex items-center justify-center">
                <img src={comcubesIcon} alt="COMCUBES" className="w-16 h-16" />
              </div>

            </div>
            <Button 
              variant="outline" 
              onClick={() => setLocation('/')}
              className="flex items-center space-x-2"
            >
              <ArrowLeft className="h-4 w-4" />
              <span>Back to Home</span>
            </Button>
          </div>
        </div>
      </header>

      <div className="max-w-2xl mx-auto px-4 py-12">
        <Card>
          <CardContent className="p-12 text-center">
            {/* Back Navigation Button */}
            <div className="flex justify-start mb-6">
              <Button 
                variant="ghost" 
                size="sm"
                onClick={() => setStep('form')}
                className="flex items-center gap-2 text-gray-600 hover:text-gray-900"
              >
                <ArrowLeft className="h-4 w-4" />
                Edit Details
              </Button>
            </div>

            <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <Building2 className="h-8 w-8 text-blue-600" />
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mb-4">Complete Your Payment</h2>
            <p className="text-gray-600 mb-8">
              Your listing has been submitted. Complete the payment to activate your listing in the COMCUBES directory.
            </p>

            <div className="bg-gray-50 rounded-lg p-6 mb-8">
              <div className="flex justify-between items-center">
                <span className="text-lg font-medium">
                  {selectedPlan === 'basic' ? 'Basic' : 'Premium'} Plan
                </span>
                <span className="text-2xl font-bold text-blue-600">
                  ${selectedPlan === 'basic' ? '60.00' : '90.00'}/quarter
                </span>
              </div>
            </div>

            <div className="space-y-6">
              <div className="space-y-4">
                <Label className="text-base font-medium">Select Payment Method</Label>
                <RadioGroup 
                  value={paymentMethod} 
                  onValueChange={(value) => setPaymentMethod(value as 'paypal' | 'paystack')}
                  className="space-y-3"
                >
                  <div className="flex items-center space-x-3 border rounded-lg p-4 cursor-pointer hover:bg-gray-50 transition-colors" onClick={() => setPaymentMethod('paystack')}>
                    <RadioGroupItem value="paystack" id="paystack" data-testid="radio-paystack" />
                    <img src={paystackLogo} alt="Paystack" className="h-6 w-auto object-contain" />
                    <Label htmlFor="paystack" className="flex-1 cursor-pointer">
                      <div className="font-medium">Paystack</div>
                      <div className="text-sm text-gray-500">Pay securely with Paystack (a Stripe subsidiary)</div>
                    </Label>
                  </div>
                  {isPayPalEnabled && (
                    <div className="flex items-center space-x-3 border rounded-lg p-4 cursor-pointer hover:bg-gray-50 transition-colors" onClick={() => setPaymentMethod('paypal')}>
                      <RadioGroupItem value="paypal" id="paypal" data-testid="radio-paypal" />
                      <img src={paypalLogo} alt="PayPal" className="h-6 w-auto object-contain" />
                      <Label htmlFor="paypal" className="flex-1 cursor-pointer">
                        <div className="font-medium">PayPal (Account may be required)</div>
                        <div className="text-sm text-gray-500">Alternative payment option</div>
                      </Label>
                    </div>
                  )}
                </RadioGroup>
              </div>

              <Button 
                onClick={handlePayment}
                size="lg"
                className="w-full whitespace-nowrap overflow-hidden"
                disabled={paymentMutation.isPending}
                data-testid="button-proceed-payment"
              >
                {paymentMutation.isPending 
                  ? 'Processing...' 
                  : paymentMethod === 'paypal' ? 'Pay with PayPal' : 'Pay with Paystack'
                }
              </Button>

              <div className="text-sm text-gray-500 text-center">
                {paymentMethod === 'paypal' 
                  ? 'Secure payment powered by PayPal. All transactions in USD.'
                  : 'Secure payment powered by Paystack. Supports cards and Apple Pay.'
                }
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );

  // Success step component  
  const renderSuccess = () => (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center py-4">
            <div className="flex items-center cursor-pointer hover:opacity-80 transition-opacity" onClick={() => setLocation('/')}>
              <div className="w-16 h-16 mr-3 flex items-center justify-center">
                <img src={comcubesIcon} alt="COMCUBES" className="w-16 h-16" />
              </div>

            </div>
            <Button 
              variant="outline" 
              onClick={() => setLocation('/')}
              className="flex items-center space-x-2"
            >
              <ArrowLeft className="h-4 w-4" />
              <span>Back to Home</span>
            </Button>
          </div>
        </div>
      </header>

      <div className="max-w-2xl mx-auto px-4 py-12">
        <Card>
          <CardContent className="p-12 text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <CheckCircle className="h-8 w-8 text-green-600" />
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mb-4">
              {isWaitlisted ? 'Added to Waitlist!' : 'Application Submitted Successfully!'}
            </h2>
            <p className="text-gray-600 mb-8">
              {isWaitlisted 
                ? 'Thank you for your interest in COMCUBES! All slots for this industry are currently occupied. You have been added to our waitlist and we will contact you as soon as a slot becomes available.'
                : 'Thank you for choosing COMCUBES for your business listing. Our team will review your application and contact you within 48 hours with next steps and payment information.'
              }
            </p>
            <Button onClick={() => setLocation('/')} size="lg">
              Return to Home
            </Button>
          </CardContent>
        </Card>
      </div>
    </div>
  );

  // Render based on current step
  if (step === 'payment') {
    return renderPayment();
  }

  if (step === 'success') {
    return renderSuccess();
  }

  // Default form step
  if (false) {
    return (
      <div className="min-h-screen bg-gray-50">
        <header className="bg-white shadow-sm border-b">
          <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center py-4">
              <div className="flex items-center cursor-pointer hover:opacity-80 transition-opacity" onClick={() => setLocation('/')}>
                <div className="w-16 h-16 mr-3 flex items-center justify-center">
                  <img src={comcubesIcon} alt="COMCUBES" className="w-16 h-16" />
                </div>

              </div>
              <Button 
                variant="outline" 
                onClick={() => setLocation('/')}
                className="flex items-center space-x-2"
              >
                <ArrowLeft className="h-4 w-4" />
                <span>Back to Home</span>
              </Button>
            </div>
          </div>
        </header>

        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
          <div className="text-center">
            <CheckCircle className="h-16 w-16 text-green-600 mx-auto mb-6" />
            <h1 className="text-3xl font-bold text-gray-900 mb-4">
              {isWaitlisted ? 'Added to Waitlist!' : 'Application Submitted Successfully!'}
            </h1>
            <p className="text-lg text-gray-600 mb-8">
              {isWaitlisted 
                ? 'Thank you for your interest in COMCUBES! All slots for this industry are currently occupied. You have been added to our waitlist and we will contact you as soon as a slot becomes available.'
                : 'Thank you for choosing COMCUBES for your business listing. Our team will review your application and contact you within 48 hours with next steps and payment information.'
              }
            </p>
            <Button onClick={() => setLocation('/')} size="lg">
              Return to Home
            </Button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <SEOHead 
        title="List Your Company - Join COMCUBES Global Business Directory"
        description="List your company in COMCUBES Global Business Directory. Choose from Basic or Premium plans to increase your business visibility worldwide."
        keywords={[
          "list company", "business directory", "company listing", "business visibility",
          "global directory", "business registration", "company profile", "business promotion"
        ]}
        canonicalUrl="https://comcubes.com/list-company"
        structuredData={createBreadcrumbStructuredData([
          { name: "Home", url: "https://comcubes.com/" },
          { name: "List Your Company", url: "https://comcubes.com/list-company" }
        ])}
      />

      <header className="bg-white shadow-sm border-b">
