          {/* Step Content */}
          {step === 'form' && renderForm()}
          {step === 'payment' && renderPayment()}
          {step === 'success' && renderSuccess()}
          </div>

          {/* Right Sidebar - Advertisement Banner - 160x600 */}
          <div className="hidden lg:block flex-shrink-0">
            <BannerAd 
