const SECTORS = [
  {
    fileName: 'deepseek_csv_20251009_4c36bb_ Media and Entertainment_1760042926112.txt',
    sectorName: 'Media and Entertainment'
  },
  {
    fileName: 'deepseek_csv_20251009_bc1b7f_Professional Services_1760042948267.txt',
